(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[6778],{3895:(t,n,a)=>{"use strict";a.r(n),a.d(n,{data:()=>s});const s={key:"v-2832f20c",path:"/python/data-type/number/",title:"Arithmetic Operator",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:3,title:"Floor Division",slug:"floor-division",children:[]},{level:3,title:"Modulus",slug:"modulus",children:[]},{level:2,title:"Order of Operations",slug:"order-of-operations",children:[]}],filePathRelative:"python/data-type/number/README.md",git:{updatedTime:162676698e4,contributors:[]}}},5142:(t,n,a)=>{"use strict";a.r(n),a.d(n,{default:()=>b});var s=a(6252);const e=(0,s.uE)('<h1 id="arithmetic-operator" tabindex="-1"><a class="header-anchor" href="#arithmetic-operator" aria-hidden="true">#</a> Arithmetic Operator</h1><p>Arithmetic = อะไรซักอย่างที่มันเกี่ยวกับคณิตศาสตร์<br> Arithmetic Operator = การทำสี่งต่างๆ กับตัวแปร เพื่อเอาไว้คำนวณเลขโดยเฉพาะ</p><p>ตัวอย่างประเภท Arithmetic Operator</p><table><thead><tr><th style="text-align:left;"><strong>สัญลักษณ์</strong></th><th>+</th><th>-</th><th>*</th><th>/</th><th>//</th><th>%</th><th>**</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>เรียกว่า</strong></td><td>Add</td><td>Subtract</td><td>Multiply</td><td>Divide</td><td>Floor Division</td><td>Modulus</td><td>Exponent</td></tr><tr><td style="text-align:left;"><strong>ตัวอย่างการใช้</strong></td><td>2+3</td><td>2-3</td><td>2*3</td><td>2/3</td><td>2//3</td><td>2&amp;3</td><td>2**3</td></tr><tr><td style="text-align:left;"><strong>ผลลัพท์</strong></td><td>5</td><td>-1</td><td>6</td><td>0.66666</td><td>0</td><td>2</td><td>8</td></tr></tbody></table><p>น้องๆอาจจะยังเห็น floor division และ modulus มาก่อนเลย พี่มงจะสอนแบบรวบรัดให้นะครับ</p><h3 id="floor-division" tabindex="-1"><a class="header-anchor" href="#floor-division" aria-hidden="true">#</a> Floor Division</h3><p>เป็นการทำการหาร แล้วค่อย <strong>ปัดเศษลงไปเป็นเลขจำนวนเต็ม</strong></p><h3 id="modulus" tabindex="-1"><a class="header-anchor" href="#modulus" aria-hidden="true">#</a> Modulus</h3><p>เป็นการหาร เพื่อ <strong>เอาแค่เศษของการหาร</strong></p><p>ตัวอย่าง</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>value_a <span class="token operator">=</span> <span class="token number">2</span>\nvalue_b <span class="token operator">=</span> <span class="token number">3</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span>value_a <span class="token operator">+</span> value_b<span class="token punctuation">)</span>    <span class="token comment"># แสดงผลลัพท์ 5</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>value_a <span class="token operator">-</span> value_b<span class="token punctuation">)</span>    <span class="token comment"># แสดงผลลัพท์ -1</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>value_a <span class="token operator">*</span> value_b<span class="token punctuation">)</span>    <span class="token comment"># แสดงผลลัพท์ 6</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>value_a <span class="token operator">/</span> value_b<span class="token punctuation">)</span>    <span class="token comment"># แสดงผลลัพท์ 0.666666...... (ไปเรื่อยๆ)</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>value_a <span class="token operator">//</span> value_b<span class="token punctuation">)</span>   <span class="token comment"># แสดงผลลัพท์ 0</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>value_a <span class="token operator">%</span> value_b<span class="token punctuation">)</span>    <span class="token comment"># แสดงผลลัพท์ 2</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>value_a <span class="token operator">**</span> value_b<span class="token punctuation">)</span>   <span class="token comment"># แสดงผลลัพท์ 8</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>อย่าลืมว่าน้องๆจะต้องแปลงเป็นตัวเลขซะก่อนที่จะเล่นอะไรพวกนี้เนอะ<br> แล้วถ้าพี่ไม่เปลี่ยนหล่ะ เช่น <code>&quot;2&quot; + &quot;2&quot;</code> หรือ <code>2 + &quot;2&quot;</code> จะได้อะไรเอ่ย มีค่าเท่ากันหรือเปล่าครับ</p></div><h2 id="order-of-operations" tabindex="-1"><a class="header-anchor" href="#order-of-operations" aria-hidden="true">#</a> Order of Operations</h2><p>ด้วยจากว่า หากมีสมการแบบนี้ <code>112 + 215 * 482 - 54 / 4782</code> แล้วคอมจะรู้หมือไร่ ว่าจะต้องคำนวณอันไหนก่อน และน้องจะรู้หมือไร่ ว่ามันจะได้ผลลัพท์เหมือนกันหรือเปล่า ถ้าน้องเรียงลำดับการคำนวณไม่เหมือน Python</p>',14),o=(0,s.Uk)("ดังนั้น Python จึงใช้กฎ PEMDAS เพื่อเป็นการเรียงลำดับของการคำนวณคณิตศาสตร์ครับ"),r=(0,s.Wm)("br",null,null,-1),p=(0,s.Uk)(" อะไรคือ PEMDAS ก็ดูเอาละกันครับ "),d={href:"http://study.com/academy/lesson/what-is-pemdas-definition-rule-examples.html",target:"_blank",rel:"noopener noreferrer"},l=(0,s.Uk)("study.com/academy/lesson/what-is-pemdas-definition-rule-examples.html"),i=(0,s.uE)("<p>โดยพี่ก็จะขอสรุปไว้ประมาณนี้แล้วกันครับ ว่ามันย่อมาจากอะไร</p><table><thead><tr><th><strong>P</strong></th><th><strong>E</strong></th><th><strong>M</strong></th><th><strong>D</strong></th><th><strong>A</strong></th><th><strong>S</strong></th></tr></thead><tbody><tr><td><strong>P</strong>arenthesis<br>วงเล็บ</td><td><strong>E</strong>xponential<br>เลขยกกำลัง</td><td><strong>M</strong>ultiplication<br>คูณ</td><td><strong>D</strong>ivision<br>หาร</td><td><strong>A</strong>ddition<br>บวก</td><td><strong>S</strong>utraction<br>ลบ</td></tr><tr><td>()</td><td>**</td><td>*</td><td>/</td><td>+</td><td>-</td></tr></tbody></table><p>นั่นคือจะเรื่มทำในวงเล็บก่อน (Parenthesis) แล้วค่อยทำเลขยกกำลัง (Exponent) ตามด้วยคูณ (Multiply) หาร (Divide) บวก (Add) ลบ (Subtract) ตามลำดับ</p>",3),c=(0,s.Uk)("หากน้องๆ ยังไม่แม่นการคำนวณเลขแบบนี้ ก็สามารถศึกษาต่อได้จาก "),u={href:"https://www.khanacademy.org/math/pre-algebra/pre-algebra-arith-prop/pre-algebra-order-of-operations/v/introduction-to-order-of-operations",target:"_blank",rel:"noopener noreferrer"},h=(0,s.Uk)("Khan Academy"),m=(0,s.Uk)(" ครับ"),b={render:function(t,n){const a=(0,s.up)("OutboundLink");return(0,s.wg)(),(0,s.j4)(s.HY,null,[e,(0,s.Wm)("p",null,[o,r,p,(0,s.Wm)("a",d,[l,(0,s.Wm)(a)])]),i,(0,s.Wm)("p",null,[c,(0,s.Wm)("a",u,[h,(0,s.Wm)(a)]),m])],64)}}}}]);